import{_ as e,o as a,c as t,a2 as i}from"./chunks/framework.IwO0Hdn_.js";const p=JSON.parse('{"title":"[LOGIC / BUSINESS] F-04.4 — Hilo de Comentarios Múltiples","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-04.4_hilo_comentarios.md","filePath":"backlog/F-04.4_hilo_comentarios.md","lastUpdated":null}'),n={name:"backlog/F-04.4_hilo_comentarios.md"};function r(s,o,c,d,l,m){return a(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="logic-business-f-04-4-—-hilo-de-comentarios-multiples" tabindex="-1">[LOGIC / BUSINESS] F-04.4 — Hilo de Comentarios Múltiples <a class="header-anchor" href="#logic-business-f-04-4-—-hilo-de-comentarios-multiples" aria-label="Permalink to &quot;[LOGIC / BUSINESS] F-04.4 — Hilo de Comentarios Múltiples&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-04 — Histórico de Logs Archivados</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Logic / Business</code><strong>Secundaria:</strong> <code>UI / Presentation</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire + Laravel + Base de Datos)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-04.1_vista_historico_pestana.html">F-04.1</a></td><td>Vista histórico y detalle de archivado disponibles</td></tr><tr><td><a href="./F-03.3_editor_rich_text.html">F-03.3</a></td><td>Editor TipTap 2 instalado y validado</td></tr><tr><td><a href="./F-05.5_usuarios_mock_session.html">F-05.5</a></td><td>Usuario autenticado en sesión para autoría de comentarios y <code>CommentPolicy</code></td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero poder añadir múltiples comentarios a un log archivado a lo largo del tiempo Para documentar el seguimiento de una incidencia o añadir contexto adicional tras el archivado inicial</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Añadir comentario):</strong> Dado que estoy en la vista detalle de un log archivado, cuando escribo un nuevo comentario y pulso &quot;Añadir comentario&quot;, entonces el comentario aparece al final del hilo con su fecha y hora.</li><li>[ ] <strong>Escenario 2 (Múltiples comentarios):</strong> Dado que un log archivado tiene 5 comentarios, cuando abro su detalle, entonces veo todos los comentarios en orden cronológico ascendente (el primero arriba, el más reciente abajo).</li><li>[ ] <strong>Escenario 3 (Comentario vacío):</strong> Dado que intento enviar un comentario vacío, cuando pulso &quot;Añadir comentario&quot;, entonces se muestra un error de validación y no se persiste nada.</li><li>[ ] <strong>Escenario 4 (Primer comentario obligatorio):</strong> Dado que F-03.2 exige comentario al archivar, cuando se crea el hilo, entonces el primer comentario siempre existe (nunca habrá un hilo vacío).</li><li>[ ] <strong>Escenario 5 (Edición por autor):</strong> Dado que veo un comentario mío, cuando pulso el icono de editar (visible solo en mis propios comentarios), entonces puedo modificar el contenido y guardar. Los comentarios de otros usuarios no muestran el botón de editar.</li><li>[ ] <strong>Escenario 6 (Input sticky):</strong> Dado que el hilo tiene muchos comentarios y hago scroll, cuando bajo hasta el final, entonces el campo de nuevo comentario siempre está visible al fondo del panel (sticky).</li><li>[ ] <strong>Requisito Técnico:</strong> Componente Livewire <code>CommentSection</code> con Livewire Actions <code>addComment()</code> y <code>updateComment(id, content)</code>. Policy <code>CommentPolicy@update</code> verifica <code>user_id</code>. Contenido sanitizado con HTMLPurifier antes de persistir (STRIDE T-RTE-01).</li></ul>',12)])])}const h=e(n,[["render",r]]);export{p as __pageData,h as default};
